        if (frm.doc.product === "Equity") {
            frm.set_df_property('task_status', 'options', [
                'Not Started',
                'Completed',
            ]);

        } else if (frm.doc.product === "Bonds") {
            frm.set_df_property('task_status', 'options', [
                'Not Started',
                'Completed',
                'In Progress',
                'Qty Not Available',
                'Maturity Bond',
                'Rejected',
                'Cancelled'
            ]);
        } else if (frm.doc.product === "Mutual Funds") {
            frm.set_df_property('task_status', 'options', [
                'Completed',
                'Not Started',
                'In Progress',
                'Rejected',
            ]);
        } else if (frm.doc.product === "Insurance") {
            frm.set_df_property('task_status', 'options', [
                'Not Started',
                'Not Eligible',
                'Not Interested',
                'No Response',
