frappe.ui.form.on('Customer', {
    refresh: function(frm) {
        // Cross Sell Lead button
        frm.add_custom_button('Create Cross Sell Lead', function() {
            let d = new frappe.ui.Dialog({
                title: 'Create Cross Sell Lead',
                fields: [
                    {
                        label: 'Entity',
                        fieldname: 'entity',
                        fieldtype: 'Select',
                        options: ['Aionion Capital', 'Aionion Insurance', 'US Subscription'],
                        reqd: 1
                    },
                    {
                        label: 'Product',
                        fieldname: 'product',
                        fieldtype: 'Select',
                        options: ['Account Opening', 'Bonds', 'Mutual Funds', 'Insurance Sales', 'Insurance Renewals', 'US Subscription'],
                        reqd: 1
                    }
                ],
                primary_action_label: 'Create Lead',
                primary_action: function(values) {
                    frappe.call({
                        method: 'aionion_custom.aionion_custom.controllers.customer.create_cross_sell_lead',
                        args: {
                            customer_name: frm.doc.name,
                            entity: values.entity,
                            product: values.product
                        },
                        callback: function(r) {
                            if (r.message) {
                                frappe.msgprint('Cross-sell lead created: ' + r.message);
                                d.hide();
                            }
                        }
                    });
                }
            });
            d.show();
        }, 'Actions');

        // View Products button
        frm.add_custom_button('View Products', function() {
            frappe.call({
                method: 'aionion_custom.aionion_custom.controllers.customer.get_customer_products',
                args: { customer_name: frm.doc.name },
                callback: function(r) {
                    if (!r.message || r.message.length === 0) {
                        frappe.msgprint('No products found for this customer.');
                        return;
                    }
                    let rows = r.message.map(p =>
                        '<tr><td>' + p.type + '</td><td>' + (p.product||'') + '</td><td>' + (p.status||'') + '</td><td>' + (p.reference||p.record||'') + '</td></tr>'
                    ).join('');
                    let html = '<table class="table table-bordered"><thead><tr><th>Type</th><th>Product</th><th>Status</th><th>Reference</th></tr></thead><tbody>' + rows + '</tbody></table>';
                    frappe.msgprint({
                        title: 'Assigned Products',
                        message: html,
                        wide: true
                    });
                }
            });
        }, 'Actions');
    }
});

