        // Force query on load
        frm.trigger('custom_sales_rm');

        // Auto set value
        if (!frm.doc.custom_sales_rm) {
            frappe.db.get_value('Employee',
                { user_id: frappe.session.user },
                'name'
            ).then(r => {
                if (r.message) {
                    frm.set_value('custom_sales_rm', r.message.name);
                }
            });
        }

        // Lock field (optional)
        frm.set_df_property('custom_sales_rm', 'read_only', 1);
    }
});

