// ─────────────────────────────────────────────
//  MAIN LOADER — calls all 3 server methods
// ─────────────────────────────────────────────
function load_call_dashboard(frm) {

    // Default date range = today
    const today = frappe.datetime.get_today();

    // Call all 3 server scripts in parallel
    Promise.all([

        frappe.call({
            method: "aionion.api.get_call_log_summary",
            args: { from_date: today, to_date: today }
        }),

        frappe.call({
            method: "aionion.api.get_hrms_hierarchy"
        }),

        frappe.call({
            method: "aionion.api.get_calls_per_employee",
            args: { from_date: today, to_date: today }
        })

    ]).then(([summaryRes, hierarchyRes, perEmpRes]) => {

        const summary   = summaryRes.message;
        const hierarchy = hierarchyRes.message;
        const perEmp    = perEmpRes.message;

        // Render each section
        render_kpi_cards(summary);
        render_org_chart(hierarchy, perEmp);
        render_leaderboard(perEmp);
        render_hourly_chart(summary.raw);
    });
}

// ─────────────────────────────────────────────
//  KPI CARDS  (total / incoming / outgoing / missed)
// ─────────────────────────────────────────────
function render_kpi_cards(summary) {

    const wrapper = $(`
        <div class="aionion-kpi-row">
            <div class="aionion-kpi" style="border-left:3px solid #1D9E75">
                <div class="kpi-label">Total Calls</div>
                <div class="kpi-val">${summary.total}</div>
            </div>
            <div class="aionion-kpi" style="border-left:3px solid #1D9E75">
                <div class="kpi-label">Incoming</div>
                <div class="kpi-val" style="color:#0F6E56">
                    ↙ ${summary.incoming}
                </div>
            </div>
            <div class="aionion-kpi" style="border-left:3px solid #D85A30">
                <div class="kpi-label">Outgoing</div>
                <div class="kpi-val" style="color:#D85A30">
                    ↗ ${summary.outgoing}
                </div>
            </div>
            <div class="aionion-kpi" style="border-left:3px solid #BA7517">
                <div class="kpi-label">Missed</div>
                <div class="kpi-val" style="color:#BA7517">
                    ${summary.missed}
                </div>
            </div>
        </div>
    `);

    frm.dashboard.add_section(wrapper[0], "Call Summary");
}

// ─────────────────────────────────────────────
//  ORG CHART  (recursive tree from HRMS)
// ─────────────────────────────────────────────
function render_org_chart(roots, perEmp) {

    // Build a fast lookup: user_id → call counts
    const callMap = {};
    perEmp.forEach(e => { callMap[e.user_id] = e; });

    // Recursively build HTML nodes
    function buildNode(emp) {
        const c = callMap[emp.user_id] || {};
        const children = (emp.children || [])
            .map(buildNode).join("");

        return `
            <div class="aionion-org-node">
                <div class="org-card">
                    <div class="org-name">${emp.employee_name}</div>
                    <div class="org-role">${emp.designation || ""}</div>
                    <div class="org-pills">
                        <span class="pill-in">↙ ${c.incoming || 0}</span>
                        <span class="pill-out">↗ ${c.outgoing || 0}</span>
                    </div>
                </div>
                ${children
                    ? `<div class="org-children">${children}</div>`
                    : ""}
            </div>
        `;
    }

    const treeHTML = roots.map(buildNode).join("");
    const wrapper  = $(`
        <div class="aionion-org-tree">${treeHTML}</div>
    `);

    frm.dashboard.add_section(wrapper[0], "Team Hierarchy");
}

// ─────────────────────────────────────────────
//  LEADERBOARD  (sorted table)
// ─────────────────────────────────────────────
function render_leaderboard(perEmp) {

    const rows = perEmp.map((e, i) => `
        <tr>
            <td>${i + 1}</td>
            <td><b>${e.employee_name}</b></td>
            <td>${e.department || "-"}</td>
            <td style="color:#0F6E56">↙ ${e.incoming || 0}</td>
            <td style="color:#D85A30">↗ ${e.outgoing || 0}</td>
            <td style="color:#BA7517">${e.missed || 0}</td>
            <td><b>${e.total_calls || 0}</b></td>
        </tr>
    `).join("");

    const table = $(`
        <table class="aionion-leaderboard">
            <thead>
                <tr>
                    <th>#</th><th>Agent</th><th>Dept</th>
                    <th>In</th><th>Out</th>
                    <th>Missed</th><th>Total</th>
                </tr>
            </thead>
            <tbody>${rows}</tbody>
        </table>
    `);

    frm.dashboard.add_section(table[0], "Agent Leaderboard");
}

// ─────────────────────────────────────────────
//  HOURLY CHART  (Chart.js bar chart)
// ─────────────────────────────────────────────
function render_hourly_chart(rawCalls) {

    // Group calls by hour
    const hours = Array.from({length: 24}, (_, i) => i);
    const incoming = Array(24).fill(0);
    const outgoing = Array(24).fill(0);

    rawCalls.forEach(call => {
        const h = new Date(call.creation).getHours();
        if (call.type === "Incoming") incoming[h]++;
        if (call.type === "Outgoing") outgoing[h]++;
    });

    const canvas = $('<canvas id="aionion_hourly_chart"></canvas>');
    frm.dashboard.add_section(canvas[0], "Calls by Hour");

    new Chart(document.getElementById("aionion_hourly_chart"), {
        type: "bar",
        data: {
            labels: hours.map(h => h + ":00"),
            datasets: [
                {
                    label: "Incoming",
                    data: incoming,
                    backgroundColor: "#1D9E75"
                },
                {
                    label: "Outgoing",
                    data: outgoing,
                    backgroundColor: "#D85A30"
                }
            ]
        },
        options: {
            responsive: true,
            plugins: { legend: { position: "top" } },
            scales: { x: { stacked: false }, y: { beginAtZero: true } }
        }
    });
}

frappe.ui.form.on('US Subscription Record', {
    refresh: function(frm) {
        if (!frm.is_new() && frappe.user.has_role('US Subscription Admin')) {
            // Approve Payment Button
            if (frm.doc.payment_status !== 'Approved') {
                frm.add_custom_button('✅ Approve Payment', function() {
                    frappe.confirm(
                        'Approve payment for ' + frm.doc.client_name + '?',
                        function() {
                            frappe.call({
                                method: 'aionion_custom.aionion_custom.controllers.crm_lead.approve_us_subscription_payment',
                                args: { us_record_name: frm.doc.name },
                                freeze: true,
                                callback: function(r) {
                                    frappe.msgprint({ message: 'Payment Approved!', indicator: 'green' });
                                    frm.reload_doc();
                                }
                            });
                        }
                    );
                }, 'Payment Actions').css({'color': 'white', 'background-color': '#28a745'});
            }

            // Reject Payment Button
            if (frm.doc.payment_status !== 'Rejected') {
                frm.add_custom_button('❌ Reject Payment', function() {
                    frappe.prompt(
                        { label: 'Rejection Reason', fieldtype: 'Small Text', reqd: 1 },
                        function(values) {
                            frappe.call({
                                method: 'aionion_custom.aionion_custom.controllers.crm_lead.reject_us_subscription_payment',
                                args: { us_record_name: frm.doc.name, reason: values.value },
                                freeze: true,
                                callback: function(r) {
                                    frappe.msgprint({ message: 'Payment Rejected!', indicator: 'red' });
                                    frm.reload_doc();
                                }
                            });
                        },
                        'Reject Payment',
                        'Reject'
                    );
                }, 'Payment Actions').css({'color': 'white', 'background-color': '#dc3545'});
            }
        }

        // Show payment status as color indicator
        if (frm.doc.payment_status) {
            const color = frm.doc.payment_status === 'Approved' ? 'green'
                : frm.doc.payment_status === 'Rejected' ? 'red' : 'orange';
            frm.page.set_indicator(frm.doc.payment_status, color);
        }
    }
});

frappe.listview_settings["CRM Lead"] = frappe.listview_settings["CRM Lead"] || {};

const _orig = frappe.listview_settings["CRM Lead"].onload;
frappe.listview_settings["CRM Lead"].onload = function(listview) {
    if (_orig) _orig(listview);

    // Export Button
    listview.page.add_inner_button("⬇ Export CSV", function() {
        frappe.show_alert({message: "Exporting...", indicator: "blue"});
        fetch("/api/method/aionion_custom.api.lead_us_import_export.export_csv", {
            method: "GET",
            headers: {"X-Frappe-CSRF-Token": frappe.csrf_token}
        })
        .then(r => r.blob())
        .then(blob => {
            const a = document.createElement("a");
            a.href = URL.createObjectURL(blob);
            a.download = "lead_us_export.csv";
            a.click();
            frappe.show_alert({message: "✅ Export complete", indicator: "green"});
        })
        .catch(e => frappe.show_alert({message: "❌ Export failed: " + e.message, indicator: "red"}));
    });

    // Import Button
    listview.page.add_inner_button("⬆ Import CSV", function() {
        new frappe.ui.FileUploader({
            restrictions: {allowed_file_types: [".csv"]},
            on_success: function(file) {
                frappe.show_alert({message: "Importing...", indicator: "blue"});
                frappe.call({
                    method: "aionion_custom.api.lead_us_import_export.import_csv",
                    args: {file_url: file.file_url},
                    freeze: true,
                    freeze_message: "Importing records...",
                    callback: function(r) {
                        const res = r.message;
