// ── Poll for incoming/active calls ───────────────────────────────────────────

var _customerCallShownIds = new Set();
var _customerCallPollTimer = null;

function checkForActiveCalls(call) {
	if (_customerCallPollTimer) return;

	function poll() {
		if (document.getElementById('smartflo-call-widget')) return;

		frappe.call({
			method: 'tata_tele_service.tata_tele_service.doctype.tata_tele_settings.tata_tele_settings.get_live_calls',
			args: {},
			callback: function(r) {
				var data = r.message;
				if (!data || !data.agent_number) return;
				var liveCalls = Array.isArray(data.data) ? data.data : [];

				for (var i = 0; i < liveCalls.length; i++) {
					var c = liveCalls[i];
					var cid = c.call_id;
					if (!cid || _customerCallShownIds.has(cid)) continue;
					_customerCallShownIds.add(cid);
					var callerNumber = c.customer_number || c.source || '';
					showCallWidget(callerNumber, null, c, call);
					break;
				}
			}
		});
	}

	_customerCallPollTimer = setInterval(poll, 2500);
	poll();
}

